const UnifiedLogin={dropdownOpen: false,init(){this.setupDropdown();this.setupClickOutside();this.highlightCurrentPortal();},setupDropdown(){const toggle=document.getElementById('loginToggle');const options=document.getElementById('loginOptions');if(!toggle||!options)return;toggle.addEventListener('click',(e)=>{e.preventDefault();e.stopPropagation();this.dropdownOpen=!this.dropdownOpen;options.classList.toggle('active',this.dropdownOpen);toggle.classList.toggle('active',this.dropdownOpen);});},setupClickOutside(){document.addEventListener('click',(e)=>{const dropdown=document.querySelector('.unified-login-dropdown');if(dropdown&&!dropdown.contains(e.target)){this.closeDropdown();}});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'){this.closeDropdown();}});},closeDropdown(){const options=document.getElementById('loginOptions');const toggle=document.getElementById('loginToggle');if(options)options.classList.remove('active');if(toggle)toggle.classList.remove('active');this.dropdownOpen=false;},highlightCurrentPortal(){const path=window.location.pathname;const options=document.querySelectorAll('.login-option');options.forEach(opt=>{const href=opt.getAttribute('href');if(href&&path.includes(href.replace('.html',''))){opt.classList.add('current');}});},detectUserType(email){if(!email)return 'client';const domain=email.split('@')[1]?.toLowerCase();if(domain==='mekongmarketing.com'||domain==='mekong.agency'){return 'staff';}if(email.includes('affiliate')||email.includes('partner')){return 'affiliate';}return 'client';},getLoginUrl(userType){const urls={staff: '/login.html',client: '/portal/login.html',affiliate: '/register.html?type=affiliate'};return urls[userType]||'/login.html';},quickLogin(email){const type=this.detectUserType(email);const url=this.getLoginUrl(type);window.location.href=`${url}?email=${encodeURIComponent(email)}`;}};document.addEventListener('DOMContentLoaded',()=>{UnifiedLogin.init();});window.UnifiedLogin=UnifiedLogin;